    input_basename = os.path.basename(input_file)
    name_root, _ = os.path.splitext(input_basename)
    
    command = [
        "soffice",
        "--headless",
        "--convert-to", conversion_format,
        input_file,
        "--outdir", output_dir
    ]
    
    subprocess.run(command, check=True)
    
    # LibreOffice names the output file based on the input filename and conversion format.
    generated_file = os.path.join(output_dir, name_root + "." + conversion_format)
    
    # If the generated file name doesn't match the desired output file, rename it.
    if os.path.abspath(generated_file) != os.path.abspath(output_file):
        os.rename(generated_file, output_file)
        
